import './Informer.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import type { InformerProps } from './Informer.types';

const iconsSet = new Set(Object.values(Icons));

export const Informer = forwardRef<HTMLSpanElement, InformerProps>(
	(
		{ semantic = 'brand', size = 'medium', content, children, className, dataTestId = 'Informer', ...htmlAttributes },
		ref,
	) => {
		const hasChildren = Boolean(children);
		const isDot = content === undefined;
		const isIcon = !isDot && typeof content === 'string' && iconsSet.has(content as Icons);

		return (
			<span
				{...htmlAttributes}
				data-testid={dataTestId}
				className={classNames(
					'dsb_informer',
					hasChildren ? 'dsb_informer--with-child' : 'dsb_informer--standalone',
					className,
				)}
				ref={ref}
			>
				{children && <span className="dsb_informer__target">{children}</span>}

				<span
					className={classNames(
						'dsb_informer__badge',
						`dsb_informer__badge--semantic-${semantic}`,
						`dsb_informer__badge--${size}`,
						!hasChildren && 'dsb_informer__badge--standalone',
						isDot && 'dsb_informer__badge--dot',
						isIcon && 'dsb_informer__badge--icon',
					)}
					data-testid={`${dataTestId}-badge`}
				>
					{!isDot && !isIcon && content}
					{isIcon && (
						<span className="dsb_informer__icon">
							<Icon iconName={content as Icons} />
						</span>
					)}
				</span>
			</span>
		);
	},
);
